-- Add index_groups and seed Nifty 500
ALTER TABLE public.scanner_instruments
  ADD COLUMN IF NOT EXISTS index_groups text[] NOT NULL DEFAULT array['Nifty 50'];

UPDATE public.scanner_instruments
SET index_groups = array['Nifty 50']
WHERE index_groups IS NULL OR array_length(index_groups, 1) IS NULL;

ON CONFLICT (isin) DO UPDATE SET
  name = EXCLUDED.name,
  industry = EXCLUDED.industry,
  series = EXCLUDED.series,
  instrument_key = EXCLUDED.instrument_key,
  index_groups = CASE
    WHEN public.scanner_instruments.index_groups @> array['Nifty 50']::text[] THEN array['Nifty 50', 'Nifty 500']::text[]
    ELSE array['Nifty 500']::text[]
  END;
